module parallel2serial (
    input wire clk,
    input wire rst_n,
    input wire [3:0]d,
    output wire valid_out,
    output wire dout
);
    reg [3:0] data;
    reg [1:0] cnt;
    reg valid;

    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            cnt <= 2'd0;
            data <= 4'd0;
            valid <= 1'b0;
        end else begin
            if(cnt == 2'd3) begin
                data <= d;
                cnt <= 2'd0;
                valid <= 1'b1;
            end else begin
                data <= {data[2:0], data[3]};
                cnt <= cnt + 1;
                valid <= 1'b0;
            end
        end
    end

    assign dout = data[3];
    assign valid_out = valid;
endmodule
